        </TouchableOpacity>

        <TouchableOpacity style={[styles.cardAction, { marginLeft: 'auto' }]} onPress={onRevoke}>
          <Trash2 size={14} color="#FF4444" />
          <Text style={[styles.cardActionText, { color: '#FF4444' }]}>Revoke</Text>
        </TouchableOpacity>
      </View>
    </TouchableOpacity>
  );
}

