                >
                  {selected ? (
                    <Eye size={12} color={Colors.primary} />
                  ) : (
                    <EyeOff size={12} color={Colors.muted} />
                  )}
                  <Text style={[styles.screenChipText, selected && styles.screenChipTextActive]}>
